--- /dev/null
+++ b/src/controllers/well-known.js
@@ -0,0 +1,57 @@
+'use strict';
+
+const nconf = require('nconf');
+const user = require('../user');
+const privileges = require('../privileges');
+const helpers = require('./helpers');
+
+const wellKnownController = module.exports;
+
+wellKnownController.webfinger = async function (req, res) {
+	const resource = req.query.resource;
+
+	if (!resource || !resource.startsWith('acct:')) {
+		return res.status(400).json({ error: 'Bad Request' });
+	}
+
+	const acctPart = resource.slice('acct:'.length);
+	const atIndex = acctPart.lastIndexOf('@');
+	if (atIndex === -1) {
+		return res.status(400).json({ error: 'Bad Request' });
+	}
+
+	const hostname = acctPart.slice(atIndex + 1);
+	const expectedHostname = nconf.get('url_parsed').hostname;
+	if (hostname !== expectedHostname) {
+		return res.status(400).json({ error: 'Bad Request' });
+	}
+
+	const canView = await privileges.global.can('view:users', req.uid);
+	if (!canView) {
+		return helpers.notAllowed(req, res);
+	}
+
+	const username = acctPart.slice(0, atIndex);
+	const uid = await user.getUidByUserslug(username);
+	if (!uid) {
+		return res.status(404).json({ error: 'Not Found' });
+	}
+
+	const baseUrl = nconf.get('url');
+	const userslug = await user.getUserField(uid, 'userslug');
+
+	return res.status(200).json({
+		subject: resource,
+		aliases: [
+			`${baseUrl}/uid/${uid}`,
+			`${baseUrl}/user/${userslug}`,
+		],
+		links: [
+			{
+				rel: 'http://webfinger.net/rel/profile-page',
+				type: 'text/html',
+				href: `${baseUrl}/user/${userslug}`,
+			},
+		],
+	});
+};
